import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext();
export const useAuth = () => useContext(AuthContext);

const USER_KEY = "demo_user";
const ADMIN_EMAIL = "admin@food.com";

const CUSTOMER_DEFAULTS = {
  address: "",
  loyaltyPoints: 0,
};

const ADMIN_DEFAULTS = {
  permissions: ["MENU_EDIT"],
};

const normalizeRole = (role) => (role === "ADMIN" ? "ADMIN" : "CUSTOMER");

const normalizeUser = (candidate = {}) => {
  const inferredRole = candidate?.role || (candidate?.email === ADMIN_EMAIL ? "ADMIN" : "CUSTOMER");
  const role = normalizeRole(inferredRole);
  const base = {
    id: candidate?.id || `${role}-${candidate?.email || "demo"}`,
    name: candidate?.name || (candidate?.email ? candidate.email.split("@")[0] : "user"),
    email: candidate?.email || "",
    role,
    preferences: { newsletter: true, defaultPayment: "instapay", theme: "light", ...(candidate?.preferences || {}) },
  };

  if (role === "ADMIN") {
    return { ...base, ...ADMIN_DEFAULTS, ...candidate };
  }

  return { ...base, ...CUSTOMER_DEFAULTS, phone: candidate?.phone || "", ...candidate };
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [showLogin, setShowLogin] = useState(false);
  const [loginMode, setLoginMode] = useState("login");

  useEffect(() => {
    try {
      const raw = localStorage.getItem(USER_KEY);
      if (raw) setUser(normalizeUser(JSON.parse(raw)));
    } catch (e) {
      // ignore
    }
  }, []);

  const persistUser = (u) => {
    setUser(u);
    try {
      localStorage.setItem(USER_KEY, JSON.stringify(u));
    } catch (e) {}
  };

  const login = ({ email }) => {
    let u = normalizeUser({ email });
    try {
      const saved = JSON.parse(localStorage.getItem(USER_KEY) || "null");
      if (saved && saved.email === email) u = normalizeUser(saved);
    } catch (e) {}
    persistUser(normalizeUser(u));
  };

  const signup = ({ name, email, phone, address, role }) => {
    const normalizedRole = normalizeRole(role || (email === ADMIN_EMAIL ? "ADMIN" : "CUSTOMER"));
    const newUser = normalizeUser({
      id: `${normalizedRole}-${Date.now()}`,
      name: name || (email ? email.split("@")[0] : "user"),
      email: email || "user@demo",
      phone: phone || "",
      address: address || "",
      role: normalizedRole,
      ...(normalizedRole === "ADMIN" ? { permissions: ["MENU_EDIT", "ORDER_REVIEW"] } : { loyaltyPoints: 0 }),
    });
    persistUser(newUser);
  };

  const logout = () => {
    setUser(null);
    try {
      localStorage.removeItem(USER_KEY);
    } catch (e) {}
  };

  const updateProfile = (updates) => {
    const next = normalizeUser({ ...user, ...updates });
    persistUser(next);
  };

  const updatePreferences = (prefs) => {
    const next = normalizeUser({ ...user, preferences: { ...(user?.preferences || {}), ...prefs } });
    persistUser(next);
  };

  const switchRole = () => {
    if (!user) return;
    const targetRole = user.role === "ADMIN" ? "CUSTOMER" : "ADMIN";
    const next = normalizeUser({
      ...user,
      role: targetRole,
      ...(targetRole === "ADMIN"
        ? { permissions: user.permissions?.length ? user.permissions : ["MENU_EDIT", "ORDER_REVIEW"] }
        : { loyaltyPoints: Number(user.loyaltyPoints || 0), address: user.address || "", phone: user.phone || "" }),
    });
    persistUser(next);
  };

  const openLogin = (mode = "login") => { setLoginMode(mode); setShowLogin(true); };
  const closeLogin = () => setShowLogin(false);

  // apply theme (dark/class) to document root when preferences change
  useEffect(() => {
    try {
      const theme = user?.preferences?.theme || "light";
      const root = document.documentElement;
      if (theme === "dark") {
        root.classList.add("dark");
      } else {
        root.classList.remove("dark");
      }
    } catch (e) {}
  }, [user?.preferences?.theme]);

  return (
    <AuthContext.Provider
      value={{
        user,
        login,
        signup,
        logout,
        updateProfile,
        updatePreferences,
        switchRole,
        isLoggedIn: !!user,
        isAdmin: user?.role === "ADMIN",
        isCustomer: user?.role === "CUSTOMER",
        showLogin,
        loginMode,
        openLogin,
        closeLogin,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};
